  "inlineSchema": "// =====================================================\n//  AgriLink Madagascar — Schema Prisma\n//  Base de données : PostgreSQL\n// =====================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─────────────────────────────────────────────────────\n//  ENUMS\n// ─────────────────────────────────────────────────────\n\nenum Role {\n  producteur\n  acheteur\n  transporteur\n  admin\n}\n\nenum ListingStatus {\n  active\n  reserved\n  in_transit\n  delivered\n  removed\n}\n\nenum ReservationStatus {\n  pending\n  accepted\n  rejected\n  awaiting_transport\n  in_transit\n  delivered\n}\n\nenum DeliveryStatus {\n  available\n  accepted\n  in_transit\n  delivered\n}\n\nenum Category {\n  Fruits\n  Legumes\n  Cereales\n  Epices\n  Boissons\n  Autres\n}\n\nenum Unit {\n  kg\n  g\n  L\n  piece\n  sac\n}\n\nenum Region {\n  Analamanga\n  Atsinanana\n  Vakinankaratra\n  Boeny\n  Sava\n  Haute_Matsiatra\n  Diana\n}\n\n// ─────────────────────────────────────────────────────\n//  USER\n// ─────────────────────────────────────────────────────\n\nmodel User {\n  id        String   @id @default(cuid())\n  name      String\n  email     String   @unique\n  password  String\n  role      Role\n  phone     String?\n  avatarUrl String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  listings     Listing[] // Un producteur peut avoir plusieurs annonces\n  reservations Reservation[] // Un acheteur peut avoir plusieurs réservations\n  deliveries   Delivery[] // Un transporteur peut avoir plusieurs livraisons\n\n  @@map(\"users\")\n}\n\n// ─────────────────────────────────────────────────────\n//  LISTING (Annonce de récolte)\n// ─────────────────────────────────────────────────────\n\nmodel Listing {\n  id           String        @id @default(cuid())\n  productName  String\n  category     Category\n  quantity     Float\n  unit         Unit\n  pricePerUnit Float\n  region       Region\n  availableOn  DateTime\n  description  String?\n  imageUrl     String?\n  status       ListingStatus @default(active)\n  createdAt    DateTime      @default(now())\n  updatedAt    DateTime      @updatedAt\n\n  // Clé étrangère vers le producteur\n  producerId String\n  producer   User   @relation(fields: [producerId], references: [id], onDelete: Cascade)\n\n  // Relations\n  reservations Reservation[]\n\n  @@index([producerId])\n  @@index([status])\n  @@index([region])\n  @@index([category])\n  @@map(\"listings\")\n}\n\n// ─────────────────────────────────────────────────────\n//  RESERVATION\n// ─────────────────────────────────────────────────────\n\nmodel Reservation {\n  id         String            @id @default(cuid())\n  quantity   Float\n  totalPrice Float\n  status     ReservationStatus @default(pending)\n  createdAt  DateTime          @default(now())\n  updatedAt  DateTime          @updatedAt\n\n  // Clé étrangère vers l'annonce\n  listingId String\n  listing   Listing @relation(fields: [listingId], references: [id], onDelete: Cascade)\n\n  // Clé étrangère vers l'acheteur\n  buyerId String\n  buyer   User   @relation(fields: [buyerId], references: [id], onDelete: Cascade)\n\n  // Relations\n  delivery Delivery?\n\n  @@index([buyerId])\n  @@index([listingId])\n  @@index([status])\n  @@map(\"reservations\")\n}\n\n// ─────────────────────────────────────────────────────\n//  DELIVERY (Mission de livraison)\n// ─────────────────────────────────────────────────────\n\nmodel Delivery {\n  id        String         @id @default(cuid())\n  pickup    String // Lieu de départ (région du producteur)\n  dropoff   String // Lieu de destination\n  fee       Float? // Tarif proposé par le transporteur\n  status    DeliveryStatus @default(available)\n  createdAt DateTime       @default(now())\n  updatedAt DateTime       @updatedAt\n\n  // Clé étrangère vers la réservation (1-to-1)\n  reservationId String      @unique\n  reservation   Reservation @relation(fields: [reservationId], references: [id], onDelete: Cascade)\n\n  // Clé étrangère vers le transporteur (nullable tant que non assigné)\n  transporterId String?\n  transporter   User?   @relation(fields: [transporterId], references: [id], onDelete: SetNull)\n\n  @@index([transporterId])\n  @@index([status])\n  @@map(\"deliveries\")\n}\n",
